const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const runId =
  'run-' +
  now.getFullYear() +
  pad(now.getMonth() + 1) +
  pad(now.getDate()) +
  '-' +
  pad(now.getHours()) +
  pad(now.getMinutes()) +
  pad(now.getSeconds());

return [
  {
    json: {
      runId,
      startTime: now.toISOString(),
      startTimeFormatted: now.toLocaleString('fa-IR', { timeZone: 'Asia/Tehran' }),
      testsPath: 'cypress/e2e-final-tests',
      baseUrl: 'https://app.aihomedesign.com',
    },
  },
];

// نتایج را از فایل JSON که run-cypress.js ساخته می‌خوانیم و پارس می‌کنیم
const fs = require('fs');

const meta = $('Set Run Metadata').first().json;
const resultsFile = 'C:\\Users\\me.moslemi\\Desktop\\cypress-e2e\\cypress-results.json';

const endTime = new Date();
const startTime = new Date(meta.startTime);
const durationMs = endTime - startTime;
const durationMin = Math.floor(durationMs / 60000);
const durationSec = Math.floor((durationMs % 60000) / 1000);

let parsed = null;
let parseError = null;
try {
  if (fs.existsSync(resultsFile)) {
    parsed = JSON.parse(fs.readFileSync(resultsFile, 'utf8'));
  } else {
    parseError = 'Results file not found: ' + resultsFile;
  }
} catch (e) {
  parseError = 'Failed to parse results file: ' + e.message;
}

let passed = 0,
  failed = 0,
  pending = 0,
  skipped = 0;
const passedTests = [];
const failedTests = [];
let runnerError = false;

function cleanError(msg) {
  if (!msg) return 'Unknown error';
  return String(msg)
    .replace(/^CypressError:\s*/, '')
    .replace(/\r/g, '')
    .trim();
}

if (parsed && parsed.stats) {
  runnerError = parsed.runnerError === true;
  const s = parsed.stats;
  passed = s.passes || 0;
  failed = s.failures || 0;
  pending = s.pending || 0;
  skipped = s.skipped || 0;

  // منبع اصلی: آرایه‌های passes / failures (استاندارد mocha json reporter)
  const passArr = Array.isArray(parsed.passes) ? parsed.passes : [];
  const failArr = Array.isArray(parsed.failures) ? parsed.failures : [];

  if (passArr.length || failArr.length) {
    for (const t of passArr) {
      passedTests.push({
        title: t.fullTitle || t.title || 'Unknown test',
        duration: t.duration || 0,
      });
    }
    for (const t of failArr) {
      const errMsg = t.err ? t.err.message : '';
      failedTests.push({
        title: t.fullTitle || t.title || 'Unknown test',
        error: cleanError(errMsg),
        duration: t.duration || 0,
      });
    }
  } else if (Array.isArray(parsed.tests)) {
    // fallback: از روی آرایه tests تفکیک می‌کنیم
    for (const t of parsed.tests) {
      const hasErr = !!(t.err && t.err.message);
      const title = t.fullTitle || t.title || 'Unknown test';
      if (hasErr) {
        failedTests.push({ title, error: cleanError(t.err.message), duration: t.duration || 0 });
      } else if (t.pending) {
        // pending
      } else {
        passedTests.push({ title, duration: t.duration || 0 });
      }
    }
    if (!passed && !failed) {
      passed = passedTests.length;
      failed = failedTests.length;
    }
  }
}

const total = passed + failed + pending + skipped;
const successRate = total > 0 ? Math.round((passed / total) * 100) : 0;

let overallStatus;
if (runnerError || parseError) overallStatus = 'ERROR';
else if (total === 0) overallStatus = 'NO_TESTS';
else if (failed === 0) overallStatus = 'PASS';
else overallStatus = 'FAIL';

return [
  {
    json: {
      runId: meta.runId,
      overallStatus,
      successRate,
      stats: { passed, failed, pending, skipped, total },
      passedTests,
      failedTests,
      duration: durationMin + 'm ' + durationSec + 's',
      startTimeFormatted: meta.startTimeFormatted,
      endTimeFormatted: endTime.toLocaleString('fa-IR', { timeZone: 'Asia/Tehran' }),
      baseUrl: meta.baseUrl,
      hasErrors: failed > 0 || overallStatus === 'ERROR' || overallStatus === 'NO_TESTS',
      parseError,
      runnerError,
    },
  },
];

const d = $input.first().json;
const SLACK_LIMIT = 2900; // امن زیر سقف 3000 کاراکتری Slack

function header() {
  let icon, title;
  if (d.overallStatus === 'ERROR') {
    icon = ':warning:';
    title = 'Cypress Test Report \u2014 RUNNER ERROR';
  } else if (d.overallStatus === 'NO_TESTS') {
    icon = ':warning:';
    title = 'Cypress Test Report \u2014 NO TESTS FOUND';
  } else {
    icon = ':red_circle:';
    title = 'Cypress Test Report \u2014 FAILED';
  }
  const lines = [];
  lines.push(icon + ' *' + title + '*');
  lines.push('\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501');
  lines.push('*Run ID:* `' + d.runId + '`');
  lines.push(
    '*Summary:* :white_check_mark: ' +
      d.stats.passed +
      ' passed  |  :x: ' +
      d.stats.failed +
      ' failed  |  Total: ' +
      d.stats.total +
      '  (' +
      d.successRate +
      '%)'
  );
  lines.push('*Duration:* ' + d.duration);
  return lines;
}

const lines = header();

if (d.parseError) {
  lines.push('');
  lines.push(':warning: *' + d.parseError + '*');
}
if (d.runnerError) {
  lines.push('');
  lines.push(':warning: *Cypress crashed before running tests. See cypress-results.json.debug.txt*');
}

// تست‌های Fail شده با علت
if (d.failedTests && d.failedTests.length > 0) {
  lines.push('');
  lines.push(':x: *Failed Tests (' + d.failedTests.length + '):*');
  for (const t of d.failedTests) {
    lines.push('\u2022 *' + t.title + '*');
    const err = (t.error || 'Unknown error').substring(0, 450);
    lines.push('   ```' + err + '```');
  }
}

// تست‌های Pass شده
if (d.passedTests && d.passedTests.length > 0) {
  lines.push('');
  lines.push(':white_check_mark: *Passed Tests (' + d.passedTests.length + '):*');
  for (const t of d.passedTests) {
    lines.push('\u2022 ' + t.title);
  }
}

lines.push('');
lines.push('\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501');
lines.push('_' + d.startTimeFormatted + '  \u2192  ' + d.endTimeFormatted + '_');

let text = lines.join('\n');
if (text.length > SLACK_LIMIT) {
  text = text.substring(0, SLACK_LIMIT) + '\n\n_... (report truncated due to Slack length limit)_';
}

return [{ json: { slackText: text, ...d } }];

const d = $input.first().json;
const SLACK_LIMIT = 2900;

const lines = [];
lines.push(':large_green_circle: *Cypress Test Report \u2014 ALL PASSED*');
lines.push('\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501');
lines.push('*Run ID:* `' + d.runId + '`');
lines.push('*Summary:* :white_check_mark: ' + d.stats.passed + ' passed  |  Total: ' + d.stats.total + '  (100%)');
lines.push('*Duration:* ' + d.duration);

if (d.passedTests && d.passedTests.length > 0) {
  lines.push('');
  lines.push(':white_check_mark: *Passed Tests (' + d.passedTests.length + '):*');
  for (const t of d.passedTests) {
    lines.push('\u2022 ' + t.title);
  }
}

lines.push('');
lines.push('\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501');
lines.push('_' + d.startTimeFormatted + '  \u2192  ' + d.endTimeFormatted + '_');

let text = lines.join('\n');
if (text.length > SLACK_LIMIT) {
  text = text.substring(0, SLACK_LIMIT) + '\n\n_... (report truncated due to Slack length limit)_';
}

return [{ json: { slackText: text, ...d } }];
